def char_add_system(bible: dict | None = None) -> str:
    """캐릭터 카드 하나만 만들면 되므로 build_bible_block(전체 줄거리·회차분배·개요·대본까지 다
    들어가 수만 자) 대신 톤·기존 인물 참고에 필요한 것만 가볍게 — 안 그러면 agent 백엔드가
    max_turns(6)을 넘겨 실패함(실측, 2026-07-13)."""
    s = CHAR_ADD_ROLE
    if not bible:
        return s
    parts = []
    if bible.get("logline"):
        parts.append(f"## 로그라인\n{bible['logline']}")
    if bible.get("target"):
        parts.append(f"## 타겟층\n{bible['target']}")
    if bible.get("emotion"):
        parts.append(f"## 핵심정서\n{bible['emotion']}")
    if bible.get("characters"):
        parts.append("## 기존 등장인물 (톤·문체·관계 참고)\n" + _character_cards(bible["characters"]))
    if parts:
        s += "\n\n" + "\n\n".join(parts)
    return s


def char_add_user(name: str, request_text: str, context: str = "") -> str:
    parts = [f"새 등장인물 이름: {name}", f"작가 요청: {request_text}"]
    if context:
        parts.append(
            "\n이 이름이 이미 등장한 대본/개요/대화 속 문장들(반드시 이 내용과 모순되지 않게, "
            f"이미 확립된 역할·행동에 맞춰 카드를 만들어라 — 무관한 다른 사람을 지어내지 마라):\n{context}")
    parts.append("위 이름으로 JSON 캐릭터 카드를 만들어라.")
    return "\n".join(parts)


